#!/usr/bin/env node

const flagIndex = process.argv.indexOf('--name');
const flagValue = flagIndex !== -1 ? process.argv[flagIndex + 1] : undefined;

// CLI flag wins over env var: a flag typed at invocation is more specific
// than an ambient env var that may have been set hours ago in the shell.
const name = flagValue || process.env.NAME;

if (!name) {
  console.error('Error: provide a name via --name <value> or NAME env var');
  process.exit(1);
}

console.log(`Hello, ${name}!`);

